const C = {
  bg: '#0D1117', surface: '#161B22', surface2: '#1C2128', border: '#30363D',
  text: '#E6EDF3', muted: '#8B949E', green: '#3FB950', red: '#F85149',
  blue: '#58A6FF', amber: '#D29922', purple: '#BC8CFF', cyan: '#39D2C0',
};
const mono = "'JetBrains Mono', 'Fira Code', monospace";
const sans = "'Plus Jakarta Sans', -apple-system, sans-serif";

function fmt$(v) { return v == null ? '--' : `$${Number(v).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`; }
function fmtPct(v) { return v == null ? '--' : `${v >= 0 ? '+' : ''}${Number(v).toFixed(1)}%`; }
function fmtN(v) { return v == null ? '--' : Number(v).toLocaleString(); }

// ── Sparkline SVG ──────────────────────────────────────────────────────
function Sparkline({ points, width = 200, height = 48, color = C.green }) {
  if (!points || points.length < 2) return null;
  const vals = points.map(p => typeof p === 'number' ? p : p.equity || p.value || 0);
  const mn = Math.min(...vals), mx = Math.max(...vals), rng = mx - mn || 1;
  const path = vals.map((v, i) => {
    const x = (i / (vals.length - 1)) * width;
    const y = height - ((v - mn) / rng) * (height - 6) - 3;
    return `${i === 0 ? 'M' : 'L'}${x.toFixed(1)},${y.toFixed(1)}`;
  }).join(' ');
  const endColor = vals[vals.length - 1] >= vals[0] ? C.green : C.red;
  return (
    <svg width={width} height={height} style={{ display: 'block' }}>
      <defs>
        <linearGradient id={`sg-${color.replace('#','')}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={endColor} stopOpacity="0.3" />
          <stop offset="100%" stopColor={endColor} stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={`${path} L${width},${height} L0,${height} Z`} fill={`url(#sg-${color.replace('#','')})`} />
      <path d={path} fill="none" stroke={endColor} strokeWidth="2" strokeLinecap="round" />
    </svg>
  );
}

// ── Metric Pill ────────────────────────────────────────────────────────
function MetricPill({ label, value, color = C.text, sub }) {
  return (
    <div style={{ textAlign: 'center', padding: '16px 20px', background: C.surface, borderRadius: 12, border: `1px solid ${C.border}`, minWidth: 140, flex: 1 }}>
      <div style={{ fontFamily: mono, fontSize: 22, fontWeight: 700, color, lineHeight: 1.2 }}>{value}</div>
      <div style={{ fontFamily: sans, fontSize: 11, color: C.muted, marginTop: 4, textTransform: 'uppercase', letterSpacing: '0.5px' }}>{label}</div>
      {sub && <div style={{ fontFamily: mono, fontSize: 10, color: C.muted, marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

// ── Bot Card ───────────────────────────────────────────────────────────
function BotCard({ name, market, startEq, currentEq, returnPct, trades, status, sparkData }) {
  const isPositive = returnPct >= 0;
  const accentColor = isPositive ? C.green : C.red;
  return (
    <div style={{
      background: C.surface, borderRadius: 12, border: `1px solid ${C.border}`,
      padding: 24, display: 'flex', flexDirection: 'column', gap: 16,
      transition: 'border-color 0.2s',
    }}
    onMouseEnter={e => e.currentTarget.style.borderColor = accentColor}
    onMouseLeave={e => e.currentTarget.style.borderColor = C.border}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <div style={{ width: 8, height: 8, borderRadius: '50%', background: status === 'OK' ? C.green : C.amber, boxShadow: `0 0 6px ${status === 'OK' ? C.green : C.amber}50` }} />
            <span style={{ fontFamily: mono, fontSize: 16, fontWeight: 700, color: C.text }}>{name}</span>
            <span style={{ fontFamily: mono, fontSize: 10, color: C.muted, background: `${C.border}60`, padding: '2px 8px', borderRadius: 4 }}>{market}</span>
          </div>
          <div style={{ fontFamily: sans, fontSize: 11, color: C.muted, marginTop: 4 }}>
            {status === 'OK' ? 'Live Trading' : status}
          </div>
        </div>
        <div style={{ textAlign: 'right' }}>
          <div style={{ fontFamily: mono, fontSize: 20, fontWeight: 700, color: accentColor }}>{fmtPct(returnPct)}</div>
          <div style={{ fontFamily: mono, fontSize: 10, color: C.muted }}>return</div>
        </div>
      </div>

      <Sparkline points={sparkData} width={280} height={40} color={accentColor} />

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 12 }}>
        {[
          { l: 'Start', v: fmt$(startEq) },
          { l: 'Current', v: fmt$(currentEq) },
          { l: 'Trades', v: fmtN(trades) },
        ].map(({ l, v }) => (
          <div key={l} style={{ textAlign: 'center' }}>
            <div style={{ fontFamily: mono, fontSize: 13, fontWeight: 600, color: C.text }}>{v}</div>
            <div style={{ fontFamily: sans, fontSize: 10, color: C.muted, marginTop: 2 }}>{l}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── Strategy Row ───────────────────────────────────────────────────────
function StrategyRow({ rank, name, pnl, trades, winRate }) {
  return (
    <div style={{
      display: 'grid', gridTemplateColumns: '30px 1fr 80px 60px 70px',
      alignItems: 'center', padding: '10px 16px', borderBottom: `1px solid ${C.border}`,
      fontFamily: mono, fontSize: 12,
    }}>
      <span style={{ color: C.muted }}>#{rank}</span>
      <span style={{ color: C.text, fontWeight: 600 }}>{name.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}</span>
      <span style={{ color: pnl >= 0 ? C.green : C.red, textAlign: 'right' }}>{fmt$(pnl)}</span>
      <span style={{ color: C.muted, textAlign: 'center' }}>{trades}</span>
      <span style={{
        color: winRate >= 65 ? C.green : winRate >= 50 ? C.amber : C.red,
        textAlign: 'right',
      }}>{winRate.toFixed(1)}%</span>
    </div>
  );
}

// ── System Status Row ──────────────────────────────────────────────────
function StatusRow({ label, value, status }) {
  const dotColor = status === 'ok' || status === true ? C.green : status === 'warning' ? C.amber : C.muted;
  return (
    <div style={{
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
      padding: '8px 0', borderBottom: `1px solid ${C.border}20`,
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
        <div style={{ width: 6, height: 6, borderRadius: '50%', background: dotColor }} />
        <span style={{ fontFamily: sans, fontSize: 12, color: C.muted }}>{label}</span>
      </div>
      <span style={{ fontFamily: mono, fontSize: 12, color: C.text }}>{value}</span>
    </div>
  );
}

